12	@objc public class XPWKWebViewPool: NSObject {
13	    private var usedWebViews = Set<WKWebView>()
14	    private var idleWebViews = Set<WKWebView>()
15	    
16	    private let lock = DispatchSemaphore(value: 1)
17	    
18	    private override init() {
19	        super.init()
20	    }
21	    
22	    @objc public static let shared = XPWKWebViewPool()
23	}
24	
25	public extension XPWKWebViewPool {
26	    @objc(getWebViewWithConfiguration:) func getWebView(with configuration: WKWebViewConfiguration) -> WKWebView {
27	        lock.wait()
28	        let webView: WKWebView
29	        if !idleWebViews.isEmpty {
30	            webView = idleWebViews.popFirst()!
31	            BBLog.info("Reuse webView: \(String(describing: webView))")
32	        } else {
33	            webView = WKWebView(frame: .zero, configuration: configuration)
34	        }
35	        usedWebViews.insert(webView)
36	        lock.signal()
37	        return webView
38	    }
39	    
40	    @objc func recycle(webView: WKWebView) {
41	        reset(webView: webView)
42	        lock.wait()
43	        if usedWebViews.contains(webView) {
44	            usedWebViews.remove(webView)
45	            idleWebViews.insert(webView)
46	            BBLog.info("Recycle webView: \(String(describing: webView))")
47	        }
48	        lock.signal()
49	    }
50	}
51	
52	private extension XPWKWebViewPool {
53	    func reset(webView: WKWebView) {
54	        webView.navigationDelegate = nil
55	        webView.uiDelegate = nil
56	        webView.scrollView.delegate = nil
57	        webView.stopLoading()
58	        if webView.url?.absoluteString != "about:blank" {
59	            webView.loadHTMLString("", baseURL: nil)
60	        }
61	        
62	        resetStack(of: webView)
63	    }
64	    
65	    func resetStack(of webView: WKWebView) {
66	        let selSource = ["0x5F", "0x72", "0x65", "0x6D", "0x6F", "0x76", "0x65", "0x41", "0x6C", "0x6C", "0x49", "0x74", "0x65", "0x6D", "0x73"]
67	        let sel = KeyMap.recoverKey(selSource)
68	        
69	        typealias Function = @convention(c) (AnyObject, Selector) -> Void
70	        if let imp = class_getMethodImplementation(WKBackForwardList.self, NSSelectorFromString(sel)) {
71	            let function = unsafeBitCast(imp, to: Function.self)
72	            function(webView.backForwardList, NSSelectorFromString(sel))
73	        }
74	    }
75	}
